SELECT a.*, ste.site_nm AS site_nm, cd_seat.code_label AS etc_adj_type_cd_nm, cd_ad.code_label AS etc_adj_dir_cd_nm FROM st_settle_etc_adj a LEFT JOIN sy_site ste ON ste.site_id = a.site_id LEFT JOIN sy_code cd_seat ON cd_seat.code_grp = 'SETTLE_ETC_ADJ_TYPE' AND cd_seat.code_value = a.etc_adj_type_cd LEFT JOIN sy_code cd_ad ON cd_ad.code_grp = 'ADJ_DIR' AND cd_ad.code_value = a.etc_adj_dir_cd
ORDER BY a.settle_etc_adj_id ASC ORDER BY a.settle_etc_adj_id DESC ORDER BY a.reg_date ASC ORDER BY a.reg_date DESC ORDER BY a.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT a.*, ste.site_nm AS site_nm, cd_seat.code_label AS etc_adj_type_cd_nm, cd_ad.code_label AS etc_adj_dir_cd_nm FROM st_settle_etc_adj a LEFT JOIN sy_site ste ON ste.site_id = a.site_id LEFT JOIN sy_code cd_seat ON cd_seat.code_grp = 'SETTLE_ETC_ADJ_TYPE' AND cd_seat.code_value = a.etc_adj_type_cd LEFT JOIN sy_code cd_ad ON cd_ad.code_grp = 'ADJ_DIR' AND cd_ad.code_value = a.etc_adj_dir_cd
ORDER BY a.settle_etc_adj_id ASC ORDER BY a.settle_etc_adj_id DESC ORDER BY a.reg_date ASC ORDER BY a.reg_date DESC ORDER BY a.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

