UPDATE st_settle_etc_adj
settle_id = #{settleId}, site_id = #{siteId}, etc_adj_type_cd = #{etcAdjTypeCd}, etc_adj_dir_cd = #{etcAdjDirCd}, etc_adj_amt = #{etcAdjAmt}, etc_adj_reason = #{etcAdjReason}, settle_etc_adj_memo = #{settleEtcAdjMemo}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE settle_etc_adj_id = #{settleEtcAdjId}
